const items = $input.all();
const seen = new Set();
const now = new Date();
const sevenDaysAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
const filtered = [];

// كلمات يجب استبعادها (أخبار غير ضريبية)
const excludeKeywords = ['altın fiyat', 'dolar kur', 'borsa', 'hisse', 'bitcoin', 'kripto', 'petrol', 'doğalgaz', 'jet yakıt', 'emtia', 'ilaç geri ödeme', 'ilaç liste', 'sağlık hizmet', 'cenaze öden', 'tedavi ücret', 'hastane', 'eczane'];

for (const item of items) {
  const d = item.json;
  const title = d.title || d.headline || '';
  const link = d.link || d.url || d.guid || '';
  const pubDate = d.pubDate || d.isoDate || d.date || d.published || '';
  const description = d.contentSnippet || d.content || d.description || d.summary || '';

  if (!title) continue;

  // استبعاد الأخبار غير الضريبية
  const titleLower = title.toLowerCase();
  const descLower = description.toLowerCase();
  const combined = titleLower + ' ' + descLower;
  if (excludeKeywords.some(kw => combined.includes(kw))) continue;

  let source = d.creator || d.author || d['dc:creator'] || '';
  if (!source && title.includes(' - ')) {
    source = title.split(' - ').pop().trim();
  }
  if (!source && link) {
    try { source = new URL(link).hostname.replace('www.', ''); } catch(e) { source = 'غير معروف'; }
  }
  if (!source) source = 'غير معروف';

  const isOfficial = title.includes('Resmi Gazete') || title.includes('tebliğ') || title.includes('teblig') || title.includes('sirküler') || title.includes('GİB') || title.includes('Gelir İdaresi') || title.includes('Maliye');

  const normalizedTitle = title.toLowerCase().trim().replace(/\s+/g, ' ');
  if (seen.has(normalizedTitle)) continue;
  seen.add(normalizedTitle);

  if (pubDate) {
    const articleDate = new Date(pubDate);
    if (!isNaN(articleDate.getTime()) && articleDate < sevenDaysAgo) continue;
  }

  filtered.push({
    json: {
      title, description: description.substring(0, 500), link, source,
      sourceType: isOfficial ? 'رسمي' : 'إخباري',
      pubDate, collectedAt: now.toISOString()
    }
  });
}

filtered.sort((a, b) => {
  if (a.json.sourceType === 'رسمي' && b.json.sourceType !== 'رسمي') return -1;
  if (a.json.sourceType !== 'رسمي' && b.json.sourceType === 'رسمي') return 1;
  return new Date(b.json.pubDate || 0) - new Date(a.json.pubDate || 0);
});

const result = filtered.slice(0, 5);
if (result.length === 0) return [];
return result;

const items = $input.all();
const originalItems = $('تنظيف وتصفية الأخبار').all();

return items.map((item, index) => {
  const original = originalItems[index]?.json || {};
  let articleText = item.json.data || item.json.body || '';
  if (typeof articleText !== 'string') articleText = JSON.stringify(articleText);
  articleText = articleText.substring(0, 4000);

  const title = original.title || '';
  const source = original.source || '';
  const sourceType = original.sourceType || '';

  const prompt = 'أنت محلل أخبار ضريبية تركية خبير. تعمل لشركة Aldewan المتخصصة في الامتثال الضريبي للشركات في تركيا.

مهمتك: تحليل هذا الخبر الضريبي واستخراج التفاصيل الدقيقة من نص المقال.

تحذير مهم: إذا كان الخبر عن أسعار سلع أو ذهب أو بورصة أو تأمين صحي للمواطنين أو أدوية أو وفيات - ضع isRelevant: false.
فقط أبقِ أخبار: تبليغات ضريبية، نسب KDV، ضريبة شركات، e-fatura، beyanname، muhtasar، SGK أقساط أصحاب العمل.

العنوان: ' + title + '
المصدر: ' + source + ' (' + sourceType + ')

نص المقال:
' + articleText + '

أجب بـ JSON فقط:
{
  "isRelevant": true/false,
  "importance": "عالي/متوسط/منخفض",
  "summaryAr": "ملخص تفصيلي بالعربي (5-7 جمل) مع الأرقام والنسب والتفاصيل المحددة",
  "summaryTr": "Detaylı Türkçe özet (5-7 cümle)",
  "category": "KDV/SGK/Kurumlar/e-Fatura/Muhtasar/Stopaj/Beyanname/Genel",
  "suggestedTitle": "عنوان عربي جذاب ودقيق",
  "keyDetails": "أهم 3-5 نقاط: أرقام ونسب ومواعيد ومواد قانونية",
  "impactOnCompanies": "ماذا يجب أن تفعل الشركات عملياً؟",
  "legalReferences": "المواد القانونية المذكورة"
}';

  const body = {
    contents: [{ parts: [{ text: prompt }] }],
    generationConfig: { temperature: 0.2 }
  };

  return { json: { ...original, articleText: articleText.substring(0, 300), geminiBody: body } };
});

const items = $input.all();
const originalItems = $('استخراج النص وتحضير Gemini').all();

const results = items.map((item, index) => {
  const original = originalItems[index]?.json || {};

  let analysis = {};
  try {
    const content = item.json.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
    const cleaned = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    analysis = JSON.parse(cleaned);
  } catch (e) {
    analysis = { isRelevant: true, importance: 'متوسط', summaryAr: original.description || '', summaryTr: '', category: 'Genel', suggestedTitle: original.title || '', keyDetails: '', impactOnCompanies: '', legalReferences: '' };
  }

  if (!analysis.isRelevant) return null;

  return {
    json: {
      title: original.title || '',
      suggestedTitle: analysis.suggestedTitle || '',
      summaryAr: analysis.summaryAr || '',
      summaryTr: analysis.summaryTr || '',
      keyDetails: analysis.keyDetails || '',
      impactOnCompanies: analysis.impactOnCompanies || '',
      legalReferences: analysis.legalReferences || '',
      category: analysis.category || 'Genel',
      importance: analysis.importance || 'متوسط',
      source: original.source || '',
      sourceType: original.sourceType || '',
      sourceUrl: original.link || '',
      pubDate: original.pubDate || '',
      collectedAt: original.collectedAt || new Date().toISOString(),
      approved: '',
      status: 'جديد'
    }
  };
}).filter(item => item !== null);

if (results.length === 0) return [];
return results;
